const input = $input.first().json;
const action = input.action || 'list_bases';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.nocodb-crm&select=cred_key,cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0) {
  return [{ json: { error: 'NocoDB credentials not configured. Use add_credential to set them up.' } }];
}

const baseUrl = (creds.find(c => c.cred_key === 'nocodb_url')?.cred_value || '').replace(/\/$/, '');
const token = creds.find(c => c.cred_key === 'nocodb_token')?.cred_value;

if (!baseUrl || !token) {
  return [{ json: { error: 'NocoDB URL and API token are both required. Use add_credential to configure them.' } }];
}

const apiHeaders = {
  'xc-token': token,
  'Content-Type': 'application/json'
};

// === list_bases ===
if (action === 'list_bases') {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api/v2/meta/bases',
      headers: apiHeaders
    });

    const bases = resp.list || resp || [];
    if (!Array.isArray(bases) || bases.length === 0) {
      return [{ json: { result: 'No bases found.' } }];
    }

    let result = 'Bases (' + bases.length + '):\n\n';
    for (const b of bases) {
      result += '- **' + (b.title || b.name || '?') + '** (ID: ' + b.id + ')';
      if (b.description) result += '\n  ' + b.description.substring(0, 100);
      result += '\n';
    }
    result += '\nUse a Base ID with nocodb_list_tables to see its tables.';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list bases: ' + err.message } }];
  }

// === list_tables ===
} else if (action === 'list_tables') {
  const baseId = input.base_id;
  if (!baseId) return [{ json: { error: 'Parameter "base_id" is required. Use nocodb_list_bases to find base IDs.' } }];

  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api/v2/meta/bases/' + baseId + '/tables',
      headers: apiHeaders
    });

    const tables = resp.list || resp || [];
    if (!Array.isArray(tables) || tables.length === 0) {
      return [{ json: { result: 'No tables found in this base.' } }];
    }

    let result = 'Tables (' + tables.length + '):\n\n';
    for (const t of tables) {
      result += '- **' + t.title + '** (ID: ' + t.id + ')';
      result += '\n';
    }
    result += '\nUse a Table ID with nocodb_list_records to see its data.';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list tables: ' + err.message } }];
  }

// === list_records ===
} else if (action === 'list_records') {
  const tableId = input.table_id;
  if (!tableId) return [{ json: { error: 'Parameter "table_id" is required. Use nocodb_list_tables to find table IDs.' } }];

  try {
    let url = baseUrl + '/api/v2/tables/' + tableId + '/records';
    const params = [];
    const limit = input.limit && input.limit !== '' ? input.limit : '25';
    params.push('limit=' + limit);
    if (input.offset && input.offset !== '') params.push('offset=' + input.offset);
    if (input.where && input.where !== '') params.push('where=' + encodeURIComponent(input.where));
    if (input.sort && input.sort !== '') params.push('sort=' + encodeURIComponent(input.sort));
    if (input.fields && input.fields !== '') params.push('fields=' + encodeURIComponent(input.fields));
    url += '?' + params.join('&');

    const resp = await helpers.httpRequest({ method: 'GET', url, headers: apiHeaders });
    const records = resp.list || [];
    const pageInfo = resp.pageInfo || {};

    if (records.length === 0) {
      return [{ json: { result: 'No records found.' } }];
    }

    let result = 'Records (' + records.length;
    if (pageInfo.totalRows) result += ' of ' + pageInfo.totalRows;
    result += '):\n\n';

    for (const r of records.slice(0, 20)) {
      const id = r.Id || r.id || r.ncRecordId || '?';
      result += '**Record ' + id + '**\n';
      for (const [key, val] of Object.entries(r)) {
        if (key === 'ncRecordId' || key === 'ncRecordHash') continue;
        const display = val === null ? '(empty)' : String(val).substring(0, 200);
        result += '  ' + key + ': ' + display + '\n';
      }
      result += '\n';
    }

    if (records.length > 20) result += '(' + (records.length - 20) + ' more records not shown)';
    if (pageInfo.isLastPage === false) result += '\nMore records available — use offset to paginate.';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list records: ' + err.message } }];
  }

// === get_record ===
} else if (action === 'get_record') {
  const tableId = input.table_id;
  const recordId = input.record_id;
  if (!tableId) return [{ json: { error: 'Parameter "table_id" is required.' } }];
  if (!recordId) return [{ json: { error: 'Parameter "record_id" is required.' } }];

  try {
    const record = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api/v2/tables/' + tableId + '/records/' + recordId,
      headers: apiHeaders
    });

    let result = '**Record ' + recordId + '**\n\n';
    for (const [key, val] of Object.entries(record)) {
      if (key === 'ncRecordId' || key === 'ncRecordHash') continue;
      const display = val === null ? '(empty)' : String(val).substring(0, 500);
      result += '**' + key + '**: ' + display + '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get record: ' + err.message } }];
  }

// === create_record ===
} else if (action === 'create_record') {
  const tableId = input.table_id;
  const dataStr = input.data;
  if (!tableId) return [{ json: { error: 'Parameter "table_id" is required.' } }];
  if (!dataStr) return [{ json: { error: 'Parameter "data" is required (JSON string of field:value pairs).' } }];

  try {
    const data = typeof dataStr === 'string' ? JSON.parse(dataStr) : dataStr;

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/api/v2/tables/' + tableId + '/records',
      headers: apiHeaders,
      body: JSON.stringify(data)
    });

    const record = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const id = record.Id || record.id || record.ncRecordId || '?';
    let result = 'Record created (ID: ' + id + ')\n\n';
    for (const [key, val] of Object.entries(record)) {
      if (key === 'ncRecordId' || key === 'ncRecordHash') continue;
      result += '**' + key + '**: ' + (val === null ? '(empty)' : String(val)) + '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    if (err.message && err.message.includes('JSON')) {
      return [{ json: { error: 'Invalid JSON in data parameter: ' + err.message } }];
    }
    return [{ json: { error: 'Failed to create record: ' + err.message } }];
  }

// === update_record ===
} else if (action === 'update_record') {
  const tableId = input.table_id;
  const recordId = input.record_id;
  const dataStr = input.data;
  if (!tableId) return [{ json: { error: 'Parameter "table_id" is required.' } }];
  if (!recordId) return [{ json: { error: 'Parameter "record_id" is required.' } }];
  if (!dataStr) return [{ json: { error: 'Parameter "data" is required (JSON string of fields to update).' } }];

  try {
    const data = typeof dataStr === 'string' ? JSON.parse(dataStr) : dataStr;
    data.Id = parseInt(recordId) || recordId;

    const resp = await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/api/v2/tables/' + tableId + '/records',
      headers: apiHeaders,
      body: JSON.stringify(data)
    });

    const record = typeof resp === 'string' ? JSON.parse(resp) : resp;
    let result = 'Record ' + recordId + ' updated.\n\n';
    if (typeof record === 'object' && record !== null) {
      for (const [key, val] of Object.entries(record)) {
        if (key === 'ncRecordId' || key === 'ncRecordHash') continue;
        result += '**' + key + '**: ' + (val === null ? '(empty)' : String(val)) + '\n';
      }
    }

    return [{ json: { result } }];
  } catch (err) {
    if (err.message && err.message.includes('JSON')) {
      return [{ json: { error: 'Invalid JSON in data parameter: ' + err.message } }];
    }
    return [{ json: { error: 'Failed to update record: ' + err.message } }];
  }

// === delete_record ===
} else if (action === 'delete_record') {
  const tableId = input.table_id;
  const recordId = input.record_id;
  if (!tableId) return [{ json: { error: 'Parameter "table_id" is required.' } }];
  if (!recordId) return [{ json: { error: 'Parameter "record_id" is required.' } }];

  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: baseUrl + '/api/v2/tables/' + tableId + '/records',
      headers: apiHeaders,
      body: JSON.stringify({ Id: parseInt(recordId) || recordId })
    });
    return [{ json: { result: 'Record ' + recordId + ' deleted from table ' + tableId + '.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete record: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list_bases, list_tables, list_records, get_record, create_record, update_record, or delete_record.' } }];
}
